SELECT AVG(rating) AS average_rating
FROM model_ratings
WHERE model_id = 1;

SELECT DISTINCT model_name
FROM models
WHERE model_id IN (
    SELECT model_id
    FROM model_comments
);

SELECT model_id, MAX(rating) AS highest_rating
FROM model_ratings
GROUP BY model_id;

SELECT model_id, AVG(rating) AS average_rating
FROM model_ratings
GROUP BY model_id;

SELECT model_id
FROM model_weights
WHERE sparsity = (SELECT MAX(sparsity) FROM model_weights);

SELECT model_name
FROM models
ORDER BY creation_date DESC, model_name ASC;
